import numpy as np

def sigmoid(x):
    return 1.0 / (1.0 + np.exp(-x))

class RBM:
    def __init__(self, n_visible, n_hidden, rng=None):
        self.rng = rng or np.random.default_rng()
        scale = 0.01
        self.W = self.rng.normal(0, scale, (n_visible, n_hidden))
        self.b = np.zeros(n_visible)   # visible bias
        self.c = np.zeros(n_hidden)    # hidden bias

    def hidden_probs(self, v):
        """P(h=1 | v), shape (batch, n_hidden)"""
        return sigmoid(v @ self.W + self.c)

    def visible_probs(self, h):
        """P(v=1 | h), shape (batch, n_visible)"""
        return sigmoid(h @ self.W.T + self.b)

    def sample(self, probs):
        return (self.rng.random(probs.shape) < probs).astype(float)

    def cd1_update(self, v0, lr=0.01):
        """Contrastive Divergence-1 weight update."""
        # Positive phase
        h0_probs = self.hidden_probs(v0)
        h0       = self.sample(h0_probs)
        # Negative phase
        v1_probs = self.visible_probs(h0)
        v1       = self.sample(v1_probs)
        h1_probs = self.hidden_probs(v1)

        # Gradients (batch mean)
        dW = (v0.T @ h0_probs - v1.T @ h1_probs) / len(v0)
        db = (v0 - v1).mean(axis=0)
        dc = (h0_probs - h1_probs).mean(axis=0)

        self.W += lr * dW
        self.b += lr * db
        self.c += lr * dc

    def reconstruction_error(self, v):
        h_probs = self.hidden_probs(v)
        v_recon = self.visible_probs(h_probs)
        return np.mean((v - v_recon) ** 2)

def generate(rbm, n_samples=16, n_gibbs=500, rng=None):
    rng = rng or np.random.default_rng()
    # Start from random binary visible state
    v = (rng.random((n_samples, rbm.W.shape[0])) > 0.5).astype(float)
    for _ in range(n_gibbs):
        h = rbm.sample(rbm.hidden_probs(v))
        v = rbm.sample(rbm.visible_probs(h))
    return v   # (n_samples, 784)

samples = generate(rbm, n_samples=16, n_gibbs=500, rng=rng)
print(samples.shape)   # (16, 784) — reshape to (16, 28, 28) for display
